import{_ as a,o as e,c as n,a3 as s}from"./chunks/framework.Daqi0Atb.js";const o="/assets/06-03.Bm-Msiau.jpg",r="/assets/06-01.BCRrgxDB.jpg",i="/assets/06-02.C4guOqJc.jpg",q=JSON.parse('{"title":"06｜感知模块导论：如何优雅设计 Agent 感知层？","description":"","frontmatter":{},"headers":[],"relativePath":"courses/agent-design/06-感知模块导论：如何优雅设计Agent感知层.md","filePath":"courses/agent-design/06-感知模块导论：如何优雅设计Agent感知层.md"}'),l={name:"courses/agent-design/06-感知模块导论：如何优雅设计Agent感知层.md"};function p(d,t,c,h,g,u){return e(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="_06-感知模块导论-如何优雅设计-agent-感知层" tabindex="-1">06｜感知模块导论：如何优雅设计 Agent 感知层？ <a class="header-anchor" href="#_06-感知模块导论-如何优雅设计-agent-感知层" aria-label="Permalink to &quot;06｜感知模块导论：如何优雅设计 Agent 感知层？&quot;">​</a></h1><p><strong>作者</strong>：黄佳</p><hr><h2 id="一句话脉络" tabindex="-1">一句话脉络 <a class="header-anchor" href="#一句话脉络" aria-label="Permalink to &quot;一句话脉络&quot;">​</a></h2><p>感知不是预处理，是核心架构问题——它决定了 Agent 后面所有推理的可靠材料是什么。</p><hr><h2 id="感知-vs-记忆-为什么要拆成两个模式组" tabindex="-1">感知 vs 记忆：为什么要拆成两个模式组？ <a class="header-anchor" href="#感知-vs-记忆-为什么要拆成两个模式组" aria-label="Permalink to &quot;感知 vs 记忆：为什么要拆成两个模式组？&quot;">​</a></h2><p><img src="'+o+'" alt="感知模块在双轴矩阵中的位置"></p><p>两者都是 Context Engineering 的一部分，但关注点不同：</p><ul><li><strong>感知</strong>：回答&quot;什么信息有资格进入上下文&quot;——信息怎么选、怎么进来、优先级是什么</li><li><strong>记忆</strong>：回答&quot;信息进来之后怎么保留&quot;——跨时间的状态、历史、经验</li></ul><p>感知是<strong>入口闸</strong>，记忆是<strong>存储层</strong>。感知决定谁能进门，记忆决定进门之后谁能留下来。</p><hr><h2 id="感知的本质-注意力预算管理" tabindex="-1">感知的本质：注意力预算管理 <a class="header-anchor" href="#感知的本质-注意力预算管理" aria-label="Permalink to &quot;感知的本质：注意力预算管理&quot;">​</a></h2><p>传统软件的输入是 schema 严格定义的；Agent 的输入是自由文本 prompt。每一个进入 prompt 的 token 都在花预算：attention 预算、KV cache 空间、API 计费。</p><p><strong>感知工程解决的三个架构化问题：</strong></p><ol><li>什么信息有资格进入上下文？</li><li>什么信息应该被压缩、排序或丢弃？</li><li>什么信息必须在模型推理前就被结构化出来？</li></ol><hr><h2 id="感知是-pra-循环的入口闸" tabindex="-1">感知是 PRA 循环的入口闸 <a class="header-anchor" href="#感知是-pra-循环的入口闸" aria-label="Permalink to &quot;感知是 PRA 循环的入口闸&quot;">​</a></h2><p><img src="'+r+'" alt="PRA 循环：Perception → Reasoning → Action"></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perception → Reasoning → Action</span></span></code></pre></div><ul><li>感知把外部世界压缩成模型能处理的上下文</li><li>推理只能加工已经进入上下文的材料，不能凭空补回没看见的事实</li><li><strong>&quot;Agent 不知道 X&quot;的真相，往往是&quot;X 明明存在，但没有进入它的视野&quot;</strong></li></ul><hr><h2 id="长上下文的陷阱" tabindex="-1">长上下文的陷阱 <a class="header-anchor" href="#长上下文的陷阱" aria-label="Permalink to &quot;长上下文的陷阱&quot;">​</a></h2><p>Liu 等人在 TACL 2024 的论文《Lost in the Middle》发现：模型使用长上下文时，对开头和结尾的信息更敏感，中间位置的关键信息更容易被忽略。</p><p><strong>窗口变长不会自动解决问题</strong>，只是把&quot;没检索到&quot;变成了&quot;检索到了但没用上&quot;。</p><hr><h2 id="感知工程-vs-传统工程-同源" tabindex="-1">感知工程 vs 传统工程（同源） <a class="header-anchor" href="#感知工程-vs-传统工程-同源" aria-label="Permalink to &quot;感知工程 vs 传统工程（同源）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>传统工程</th><th>Agent 感知</th></tr></thead><tbody><tr><td>数据库查询优化（WHERE/JOIN/LIMIT 在数据库层筛数据）</td><td>上下文分诊（在进入 prompt 前判断什么信息值得进来）</td></tr><tr><td>虚拟内存（热数据放 RAM，冷数据放磁盘）</td><td>上下文分层（P0 直接进，P2 压缩进，P3 等需要再取）</td></tr><tr><td>CDN 缓存（热门内容靠近用户）</td><td>感知优先级（高频关键信息离模型更近）</td></tr><tr><td>编辑工作（替读者筛选哪些证据该进文章）</td><td>替模型筛选信息</td></tr></tbody></table><p><strong>感知工程不是新瓶装新酒，本质上是在 LLM 这个新载体上重新实现数据库、操作系统、缓存系统早就积累过的经验。</strong></p><hr><h2 id="感知模式组-选-→-压-→-探-→-融" tabindex="-1">感知模式组：选 → 压 → 探 → 融 <a class="header-anchor" href="#感知模式组-选-→-压-→-探-→-融" aria-label="Permalink to &quot;感知模式组：选 → 压 → 探 → 融&quot;">​</a></h2><p><img src="'+i+`" alt="感知模式组总览"></p><table tabindex="0"><thead><tr><th>模式</th><th>解决的问题</th></tr></thead><tbody><tr><td>上下文分诊（Context Triage）</td><td>哪些信息应该进来，什么该挡在外面</td></tr><tr><td>语义压缩（Semantic Compaction）</td><td>信息进来之后怎么变短，但不丢关键证据</td></tr><tr><td>渐进发现（Progressive Discovery）</td><td>一开始不知道信息在哪，Agent 怎么逐步找</td></tr><tr><td>多模态融合（Multi-Modal Fusion）</td><td>图片、表格、PDF、SQL、日志这些异类信息怎么进入上下文</td></tr></tbody></table><hr><h2 id="四个工业争论" tabindex="-1">四个工业争论 <a class="header-anchor" href="#四个工业争论" aria-label="Permalink to &quot;四个工业争论&quot;">​</a></h2><ol><li><strong>RAG 还是 Agentic Search？</strong> — 提前建索引检索，还是让 Agent 自己搜索、读文件、沿着线索深入？</li><li><strong>窗口越大越好吗？</strong> — 长窗口不等于可以不筛选，塞进去之后模型能不能稳定用好才是问题。</li><li><strong>多模态内容保留为图，还是转成文本？</strong> — 核心信号在空间关系里，还是在文字内容里？</li><li><strong>分诊靠人写，还是算法自动？</strong> — 规则驱动、算法判断，还是 schema/权限强约束？</li></ol><hr><h2 id="perception-trace-agent-的行车记录仪" tabindex="-1">Perception Trace：Agent 的行车记录仪 <a class="header-anchor" href="#perception-trace-agent-的行车记录仪" aria-label="Permalink to &quot;Perception Trace：Agent 的行车记录仪&quot;">​</a></h2><p><strong>普通日志</strong>：只能看到最终回答，不知道 Agent 当时看到了什么、没看到什么</p><p><strong>Perception Trace</strong>：记录模型在开始推理之前经历了什么</p><ul><li>读了哪些文件</li><li>检索到了哪些内容</li><li>选中了哪些片段</li><li>丢弃了哪些材料</li><li>压缩了哪些历史</li><li>调用了哪些发现动作</li><li>关键证据最终落在上下文什么位置</li></ul><p><strong>实例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户问：订单为什么不能退款？</span></span>
<span class="line"><span>最终答案错</span></span>
<span class="line"><span></span></span>
<span class="line"><span>普通日志：answer = &quot;该订单已超过退款期限&quot;</span></span>
<span class="line"><span>Perception Trace：</span></span>
<span class="line"><span>  检索命中：47 条</span></span>
<span class="line"><span>  进入 context：6 条</span></span>
<span class="line"><span>  被丢弃：41 条</span></span>
<span class="line"><span>  关键证据：refund_policy_v3.md → 排序到第 38 位 → 未进入 context</span></span>
<span class="line"><span>  实际进入：refund_policy_v1.md（已过期版本）</span></span></code></pre></div><p><strong>根因暴露</strong>：不是模型的问题，是分诊规则让过期政策排到了第 38 位，没进 context。</p><hr><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p><strong>感知不是预处理，是核心架构问题。它和数据建模、API 设计、容量规划是一个量级的事情。</strong></p></blockquote><p>你把它当配菜，Agent 就会在看似聪明的输出里不断漏信号。 你把它当主菜，系统才有机会跑得稳、跑得准、跑得便宜。</p><hr><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to &quot;思考题&quot;">​</a></h2><ol><li><p>当前 Agent 的系统提示词有多少 token？有多少是&quot;为了让 Agent 知道更多&quot;塞进去的？砍掉 50%，关键任务表现会变好还是变差？</p></li><li><p>找一个最近失败或结果不稳定的 Agent 任务，复盘 Perception Trace：</p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>任务是什么：</span></span>
<span class="line"><span>Agent 最后错在哪里：</span></span>
<span class="line"><span>正确答案依赖的关键证据是什么：</span></span>
<span class="line"><span>这个证据原本在哪里：</span></span>
<span class="line"><span>它有没有进入上下文：</span></span>
<span class="line"><span>如果进了，出现在上下文什么位置：</span></span>
<span class="line"><span>如果没进，是检索没命中、分诊丢掉了，还是压缩时压没了：</span></span>
<span class="line"><span>下一版你会怎么改感知 pipeline：</span></span></code></pre></div><ol start="3"><li>同一个任务、不同长度 context（30K / 100K / 200K），看成功率怎么变化。</li></ol><hr><h2 id="关键对话总结" tabindex="-1">关键对话总结 <a class="header-anchor" href="#关键对话总结" aria-label="Permalink to &quot;关键对话总结&quot;">​</a></h2><h3 id="_1-感知-vs-记忆-最容易混的一对" tabindex="-1">1. 感知 vs 记忆：最容易混的一对 <a class="header-anchor" href="#_1-感知-vs-记忆-最容易混的一对" aria-label="Permalink to &quot;1. 感知 vs 记忆：最容易混的一对&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>感知</th><th>记忆</th></tr></thead><tbody><tr><td>角色</td><td>入口闸</td><td>存储层</td></tr><tr><td>回答</td><td>什么信息有资格进入上下文</td><td>信息进来之后怎么保留</td></tr><tr><td>类比</td><td>安检口决定谁能上飞机</td><td>行李架决定东西放哪、放多久</td></tr></tbody></table><h3 id="_2-感知不是预处理" tabindex="-1">2. 感知不是预处理 <a class="header-anchor" href="#_2-感知不是预处理" aria-label="Permalink to &quot;2. 感知不是预处理&quot;">​</a></h3><p>感知和数据建模、API 设计、容量规划是一个量级的事情：</p><blockquote><p>你把它当配菜，Agent 就会在看似聪明的输出里不断漏信号。 你把它当主菜，系统才有机会跑得稳、跑得准、跑得便宜。</p></blockquote><h3 id="_3-感知工程-×-传统工程是对应的" tabindex="-1">3. 感知工程 × 传统工程是对应的 <a class="header-anchor" href="#_3-感知工程-×-传统工程是对应的" aria-label="Permalink to &quot;3. 感知工程 × 传统工程是对应的&quot;">​</a></h3><table tabindex="0"><thead><tr><th>传统工程</th><th>Agent 感知</th></tr></thead><tbody><tr><td>数据库查询优化（WHERE/JOIN/LIMIT 在数据库层筛数据）</td><td>上下文分诊（进入 prompt 前判断什么信息值得进来）</td></tr><tr><td>虚拟内存（热数据放 RAM，冷数据放磁盘）</td><td>上下文分层（P0 直接进，P2 压缩进，P3 等需要再取）</td></tr><tr><td>CDN 缓存（热门内容靠近用户）</td><td>感知优先级（高频关键信息离模型更近）</td></tr></tbody></table><p><strong>感知工程不是新东西，本质上是在 LLM 上重新实现数据库、操作系统、缓存系统早就积累过的经验。</strong></p><h3 id="_4-pra-循环" tabindex="-1">4. PRA 循环 <a class="header-anchor" href="#_4-pra-循环" aria-label="Permalink to &quot;4. PRA 循环&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Perception → Reasoning → Action</span></span></code></pre></div><p>推理只能加工已经进入上下文的材料，不能凭空补回没看见的事实。<strong>&quot;Agent 不知道 X&quot;的真相，往往是&quot;X 明明存在，但没有进入它的视野&quot;。</strong></p><h3 id="_5-perception-trace-比普通日志多一层" tabindex="-1">5. Perception Trace：比普通日志多一层 <a class="header-anchor" href="#_5-perception-trace-比普通日志多一层" aria-label="Permalink to &quot;5. Perception Trace：比普通日志多一层&quot;">​</a></h3><p>普通日志：<code>answer = &quot;订单已超过退款期限&quot;</code>——只知道错了，不知道为什么错。</p><p>Perception Trace：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>检索命中：47 条</span></span>
<span class="line"><span>进入 context：6 条</span></span>
<span class="line"><span>被丢弃：41 条</span></span>
<span class="line"><span>关键证据：refund_policy_v3.md → 排序到第 38 位 → 未进入 context</span></span>
<span class="line"><span>实际进入：refund_policy_v1.md（已过期版本）</span></span></code></pre></div><p>根因暴露：不是模型错了，是<strong>分诊规则让过期政策排到了第 38 位，没进 context。</strong></p><h3 id="_6-感知模式组四讲预告" tabindex="-1">6. 感知模式组四讲预告 <a class="header-anchor" href="#_6-感知模式组四讲预告" aria-label="Permalink to &quot;6. 感知模式组四讲预告&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>解决什么问题</th></tr></thead><tbody><tr><td>上下文分诊（第 07 讲）</td><td>哪些信息应该进来，什么该挡在外面</td></tr><tr><td>语义压缩（第 08 讲）</td><td>信息进来之后怎么变短，但不丢关键证据</td></tr><tr><td>渐进发现（第 09 讲）</td><td>一开始不知道信息在哪，Agent 怎么逐步找</td></tr><tr><td>多模态融合（第 10 讲）</td><td>图片、表格、PDF、SQL、日志这些异类信息怎么进入上下文</td></tr></tbody></table><h3 id="_7-一句话带走" tabindex="-1">7. 一句话带走 <a class="header-anchor" href="#_7-一句话带走" aria-label="Permalink to &quot;7. 一句话带走&quot;">​</a></h3><blockquote><p><strong>感知不是预处理，是核心架构问题。它决定了 Agent 后面所有推理的可靠材料是什么——&quot;Agent 不知道 X&quot;的真相，往往是&quot;X 明明存在，但没有进入它的视野&quot;。</strong></p></blockquote>`,75)])])}const _=a(l,[["render",p]]);export{q as __pageData,_ as default};
